() => {
  const shotGroupNodes = document.querySelectorAll('.node[data-node-id]');
  let shotGroupCount = 0;
  shotGroupNodes.forEach(node => {
    const title = node.querySelector('.node-title');
    if (title && title.textContent.includes('分镜组')) {
      shotGroupCount++;
    }
  });
  return { ok: shotGroupCount > 0, shot_group_count: shotGroupCount };
}

() => {
  const nodes = document.querySelectorAll('.node[data-node-id]');
  let allPositive = true;
  let minX = Infinity;
  let minY = Infinity;
  nodes.forEach(node => {
    const x = parseInt(node.style.left) || 0;
    const y = parseInt(node.style.top) || 0;
    if (x < 0 || y < 0) allPositive = false;
    minX = Math.min(minX, x);
    minY = Math.min(minY, y);
  });
  return { ok: allPositive, min_x: minX, min_y: minY };
}

() => {
  const state = window.state || {};
  const panX = state.panX || 0;
  const panY = state.panY || 0;
  return { ok: panX <= 0 && panY <= 0, pan_x: panX, pan_y: panY };
}

async () => {
  const script = '第一幕：清晨，客厅。小李端着咖啡走向沙发并坐下，说：新的一天开始了。随后他望向窗外，听到鸟鸣与远处车辆声。第二幕：同一地点，阳光更强，小李放下杯子起身整理桌面。';
  const resp = await fetch('/api/parse-script', {
    method: 'POST',
    headers: { 'Content-Type': 'application/json' },
    body: JSON.stringify({ script_content: script, max_group_duration: 15 })
  });
  const json = await resp.json();
  const groups = json && json.data && json.data.shot_groups ? json.data.shot_groups : [];
  let allShotsHaveDuration = true;
  let shotCount = 0;
  let missingDuration = [];
  for (const group of groups) {
    if (group.shots && Array.isArray(group.shots)) {
      for (const shot of group.shots) {
        shotCount++;
        if (typeof shot.duration !== 'number' || shot.duration <= 0) {
          allShotsHaveDuration = false;
          missingDuration.push(shot.shot_id || 'unknown');
        }
      }
    }
  }
  return { ok: allShotsHaveDuration, group_count: groups.length, shot_count: shotCount, missing_duration: missingDuration, response_code: json ? json.code : null };
}

async () => {
  const script = '第一幕：清晨，客厅。小李端着咖啡走向沙发并坐下，说：新的一天开始了。';
  const resp = await fetch('/api/parse-script', {
