    body: JSON.stringify({ script_content: script, max_group_duration: 15 })
  });
  const json = await resp.json();
  const data = json.data || {};
  const hasShotGroups = Array.isArray(data.shot_groups);
  const hasDirectShots = Array.isArray(data.shots);
  let allGroupsHaveShots = true;
  if (hasShotGroups) {
    data.shot_groups.forEach(group => {
      if (!Array.isArray(group.shots)) allGroupsHaveShots = false;
    });
  }
  return { ok: hasShotGroups && !hasDirectShots && allGroupsHaveShots, has_shot_groups: hasShotGroups, has_direct_shots: hasDirectShots, all_groups_have_shots: allGroupsHaveShots };
}

async () => {
  const script = '第一幕：清晨，客厅。小李端着咖啡走向沙发并坐下，说：新的一天开始了。随后他望向窗外，听到鸟鸣与远处车辆声。';
  const resp = await fetch('/api/parse-script', {
    method: 'POST',
    headers: { 'Content-Type': 'application/json' },
    body: JSON.stringify({ script_content: script, max_group_duration: 15 })
  });
  const json = await resp.json();
  const groups = json && json.data && json.data.shot_groups ? json.data.shot_groups : [];
  let allDetailed = true;
  let minLength = Infinity;
  let tooShort = [];
  for (const group of groups) {
    if (group.shots && Array.isArray(group.shots)) {
      for (const shot of group.shots) {
        const desc = shot.opening_frame_description || '';
        const len = desc.length;
        minLength = Math.min(minLength, len);
        if (len < 50) {
          allDetailed = false;
          tooShort.push(shot.shot_id);
        }
      }
    }
  }
  return { ok: allDetailed, min_length: minLength === Infinity ? 0 : minLength, too_short: tooShort };
}

