async () => {
  const script = '第一幕：清晨，客厅。小李端着咖啡走向沙发并坐下。';
  const resp = await fetch('/api/parse-script', {
    method: 'POST',
    headers: { 'Content-Type': 'application/json' },
    body: JSON.stringify({ script_content: script, max_group_duration: 15 })
  });
  const json = await resp.json();
  const data = json.data || {};
  let allValid = true;
  let invalidIds = [];

  (data.characters || []).forEach(char => {
    if (!/^char_\d{3}$/.test(char.id)) {
      allValid = false;
      invalidIds.push({ type: 'character', id: char.id });
    }
  });

  (data.locations || []).forEach(loc => {
    if (!/^loc_\d{3}$/.test(loc.id)) {
      allValid = false;
      invalidIds.push({ type: 'location', id: loc.id });
    }
  });

  (data.shot_groups || []).forEach(group => {
    if (!/^grp_\d{3}$/.test(group.group_id)) {
      allValid = false;
      invalidIds.push({ type: 'group', id: group.group_id });
    }
    (group.shots || []).forEach(shot => {
      if (!/^s\d{3}$/.test(shot.shot_id) && !/^shot_\d{3}$/.test(shot.shot_id)) {
        allValid = false;
        invalidIds.push({ type: 'shot', id: shot.shot_id });
      }
    });
  });

  return { ok: allValid, invalid_ids: invalidIds };
}

