async () => {
  const data = window.testParsedData;
  if (!data || !data.shot_groups || data.shot_groups.length === 0) {
    return { ok: false, error: '没有shot_groups数据' };
  }

  const firstGroup = data.shot_groups[0];
  if (!firstGroup.shots || firstGroup.shots.length === 0) {
    return { ok: false, error: '没有shots数据' };
  }

  const firstShot = firstGroup.shots[0];
  const hasFields = 'db_location_id' in firstShot && 'db_location_pic' in firstShot && 'location_name' in firstShot;

  return {
    ok: hasFields,
    shot_data: {
      db_location_id: firstShot.db_location_id,
      db_location_pic: firstShot.db_location_pic,
      location_name: firstShot.location_name,
      location_id: firstShot.location_id
    }
  };
}

async () => {
  const data = window.testParsedData;
  const locations = data.locations || [];
  const shots = data.shot_groups[0].shots || [];

  let matchResults = [];
  for (const shot of shots) {
    const location = locations.find(loc => loc.id === shot.location_id);
    const hasDbId = location && location.location_db_id === window.testLocationId;
    const shotHasMatch = shot.db_location_id === window.testLocationId;

    matchResults.push({
      shot_id: shot.shot_id,
      location_id: shot.location_id,
      expected_match: hasDbId,
      actual_match: shotHasMatch,
      db_location_id: shot.db_location_id,
      location_name: shot.location_name
    });
  }

  const allCorrect = matchResults.every(r => r.expected_match === r.actual_match);
  return { ok: allCorrect, results: matchResults };
}

