() => {
  const modal = document.getElementById('shotGroupModal');
  if (!modal || !modal.classList.contains('show')) {
    return { ok: false, error: '详情弹窗未打开' };
  }

  const content = modal.querySelector('#shotGroupModalContent');
  const hasReferenceSection = content.innerHTML.includes('参考场景');
  const hasLocationImage = content.querySelector('img[alt*="参考"]') !== null;

  return {
    ok: hasReferenceSection && hasLocationImage,
    has_reference_section: hasReferenceSection,
    has_location_image: hasLocationImage
  };
}

() => {
  const locationList = document.getElementById('locationList');
  if (!locationList) return { ok: false, error: '场景列表未找到' };

  const cards = locationList.querySelectorAll('.location-card');
  if (cards.length === 0) return { ok: false, error: '没有场景卡片' };

  const firstCard = cards[0];
  const hasImage = firstCard.querySelector('img') !== null;
  const hasName = firstCard.textContent.includes('测试客厅');
  const hasId = firstCard.textContent.includes('ID:');

  return {
    ok: hasImage && hasName && hasId,
    card_count: cards.length,
    has_image: hasImage,
    has_name: hasName,
    has_id: hasId
  };
}

() => {
